package main

import (
  "context"
  "log"

  rewrite "github.com/rewritetoday/golang"
)

func main() {
  client, err := rewrite.New("rw_your_api_key")
  if err != nil { log.Fatal(err) }

  _, err = client.APIKeys.Create(context.Background(), rewrite.CreateAPIKeyOptions{
    RESTPostCreateAPIKeyBody: rewrite.RESTPostCreateAPIKeyBody{
      Name: "Jobs worker",
      Scopes: []rewrite.APIKeyScope{
        rewrite.APIKeyScopeReadTemplates,
        rewrite.APIKeyScopeReadWebhooks,
      },
    },
  })
  if err != nil { log.Fatal(err) }
}

